local StructCallRankShowInfo = LxClass("StructCallRankShowInfo", nil)
LXImport(".StructRewardItem")
function StructCallRankShowInfo:StructCallRankShowInfo()
    self.extraReward = {}               --召喚獲得信息
    self.createTime = 0                 --召唤时间
    self.rankValue = 0                  --欧气值
    self.callPlayerName = ""            --召唤玩家名字
    self.callLogId = 0                  --召唤信息日志id
end

function StructCallRankShowInfo:CreateByPb(pb)
    local resData       = JSON.decode(pb)

    self.createTime     = resData.createTime
    self.rankValue      = resData.rankValue
    self.callPlayerName = resData.callPlayerName
    self.callLogId      = resData.callLogId

    local list = {}
    for i, v in ipairs(resData.extraReward) do
        local item = StructRewardItem:New()
        item:CreateByPb(v)
        table.insert(list,item)
    end
    self.extraReward = list
end

function StructCallRankShowInfo:GetServerData()
    local data = {
        extraReward = self.extraReward,
        createTime  = self.createTime,
        rankValue   = self.rankValue,
        callPlayerName = self.callPlayerName,
        callLogId   = self.callLogId,
    }

    return data
end

return StructCallRankShowInfo